// Side-effect-only CSS imports from @fontsource — they ship .css with no JS,
// so TypeScript needs ambient declarations to accept the import.
declare module '@fontsource/bebas-neue/*'
declare module '@fontsource-variable/hanken-grotesk'
declare module '@fontsource-variable/hanken-grotesk/*'
declare module '@fontsource-variable/jetbrains-mono'
declare module '@fontsource-variable/jetbrains-mono/*'
